1	// app/src/domain/adjudication/adjudicator.ts — the pure adjudication core.
2	// adjudicateLine(input) -> decision + accumulator deltas. No I/O: it reads a snapshot
3	// and returns the deltas for the caller to persist, which is what makes it deterministic
4	// and unit-testable with plain objects (no DB for the pure cycles).
5	
6	import type { LineItem, LineItemStatus } from "../entities/line-item";
7	import type { Policy } from "../entities/policy";
8	import { formatUsd } from "../money/cents";
9	import { ReasonCode } from "../reason-codes";
10	import type { CoverageRule } from "../rules/coverage-rule";
11	
12	export type AccumulatorSnapshot = {
13	  deductibleMetCents: number;
14	  oopMetCents: number;
15	  limitUsed: number; // cents for a dollar limit, a count for a visit limit
16	};
17	
18	export type AdjudicateLineInput = {
19	  line: LineItem;
20	  policy: Policy;
21	  rule: CoverageRule | undefined; // matched by serviceCode; undefined => NO_COVERAGE
22	  serviceDate: string; // claim-level ISO date (policy-active check)
23	  acc: AccumulatorSnapshot; // read-only snapshot taken at claim start
24	  alreadyAdjudicated: boolean; // true => DUPLICATE_LINE_ITEM
25	};
26	
27	export type AdjudicateLineResult = {
28	  status: LineItemStatus; // APPROVED | DENIED (NEEDS_REVIEW only via dispute)
29	  payableCents: number; // plan pays
30	  memberResponsibilityCents: number; // member owes
31	  reasons: ReasonCode[]; // dominant code first, then any breakdown
32	  explanation: string; // EOB sentence citing the rule + the numbers used
33	  deltas: { deductibleIncCents: number; oopIncCents: number; limitInc: number };
34	};
35	
36	export function adjudicateLine(input: AdjudicateLineInput): AdjudicateLineResult {
37	  const { rule, line, policy, serviceDate, acc, alreadyAdjudicated } = input;
38	
39	  // Every gate denial shares one shape: plan pays nothing, member owes nothing here
40	  // (a non-covered service is billed to the member directly, not as cost-share), and
41	  // no accumulator is touched. A denial is a processed decision, never an error.
42	  const deny = (reason: ReasonCode, explanation: string): AdjudicateLineResult => ({
43	    status: "DENIED",
44	    payableCents: 0,
45	    memberResponsibilityCents: 0,
46	    reasons: [reason],
47	    explanation,
48	    deltas: { deductibleIncCents: 0, oopIncCents: 0, limitInc: 0 },
49	  });
50	
51	  // GATES — fire in pipeline order; the first failing gate denies the line.
52	
53	  // Cycle 7 — duplicate fingerprint already adjudicated.
54	  if (alreadyAdjudicated) {
55	    return deny(
56	      ReasonCode.DUPLICATE_LINE_ITEM,
57	      `Duplicate line: ${line.serviceCode} was already adjudicated; the plan pays ${formatUsd(0)}.`,
58	    );
59	  }
60	
61	  // Cycle 5 — service date outside the policy's active window. ISO dates compare lexically.
62	  if (serviceDate < policy.effectiveDate || serviceDate > policy.terminationDate) {
63	    return deny(
64	      ReasonCode.POLICY_NOT_ACTIVE,
65	      `Policy not active: ${serviceDate} is outside the coverage window (${policy.effectiveDate}–${policy.terminationDate}); the plan pays ${formatUsd(0)}.`,
66	    );
67	  }
68	
69	  // Cycle 2 — no benefit rule matched this service_code.
70	  if (!rule) {
71	    return deny(
72	      ReasonCode.NO_COVERAGE,
73	      `No coverage: no benefit rule applies to ${line.serviceCode}, so the plan pays ${formatUsd(0)}.`,
74	    );
75	  }
76	
77	  // Cycle 3 — the rule explicitly excludes this service.
78	  if (rule.excluded) {
79	    return deny(
80	      ReasonCode.EXCLUDED,
81	      `Excluded benefit: ${line.serviceCode} is excluded from the plan, so the plan pays ${formatUsd(0)}.`,
82	    );
83	  }
84	
85	  // Cycle 4 — the rule exists but the service is not a covered benefit.
86	  if (!rule.covered) {
87	    return deny(
88	      ReasonCode.NO_COVERAGE,
89	      `No coverage: ${line.serviceCode} is not a covered benefit, so the plan pays ${formatUsd(0)}.`,
90	    );
91	  }
92	
93	  // Cycle 6 — prior auth required but not present → clean deny.
94	  if (rule.requiresPriorAuth && !line.priorAuthPresent) {
95	    return deny(
96	      ReasonCode.PRIOR_AUTH_REQUIRED,
97	      `Prior authorization required: ${line.serviceCode} needs prior auth, which was not present; the plan pays ${formatUsd(0)}.`,
98	    );
99	  }
100	
101	  // Cycle 15 — visit limit fully consumed → whole-visit denial (no partial visit).
102	  if (rule.limit.unit === "visits" && acc.limitUsed >= rule.limit.count) {
103	    return deny(
104	      ReasonCode.LIMIT_EXCEEDED,
105	      `Limit exceeded: ${line.serviceCode} has used all ${rule.limit.count} covered visits this plan year; the plan pays ${formatUsd(0)}.`,
106	    );
107	  }
108	
109	  // Dollar limit fully exhausted (no remaining at all) → denial. A *partial* remaining is
110	  // handled after cost-share as a straddle (cycle 17), where the line stays APPROVED.
111	  if (rule.limit.unit === "dollars" && acc.limitUsed >= rule.limit.amountCents) {
112	    return deny(
113	      ReasonCode.LIMIT_EXCEEDED,
114	      `Limit exceeded: ${line.serviceCode} has reached its ${formatUsd(rule.limit.amountCents)} annual limit; the plan pays ${formatUsd(0)}.`,
115	    );
116	  }
117	
118	  // ---- Cost-share (step 7): compute the base member / plan split. Every covered line
119	  // satisfies `payable + member === billed`. The limit step below may then shift money. ----
120	  let result: AdjudicateLineResult;
121	
122	  if (rule.costShare.type === "full_coverage") {
123	    // Cycle 1 — plan pays 100%, member owes nothing, deductible/OOP untouched.
124	    result = {
125	      status: "APPROVED",
126	      payableCents: line.billedCents,
127	      memberResponsibilityCents: 0,
128	      reasons: [ReasonCode.APPROVED],
129	      explanation: `Full coverage: the plan pays 100% (${formatUsd(line.billedCents)}); you owe ${formatUsd(0)}.`,
130	      deltas: { deductibleIncCents: 0, oopIncCents: 0, limitInc: 0 },
131	    };
132	  } else if (rule.costShare.type === "copay") {
133	    // Cycle 8–9 — flat copay; waives the deductible but counts to OOP; member ≤ allowed.
134	    const allowedCents = line.billedCents;
135	    const memberCents = Math.min(rule.costShare.copayCents, allowedCents);
136	    const planCents = allowedCents - memberCents;
137	    result = {
138	      status: "APPROVED",
139	      payableCents: planCents,
140	      memberResponsibilityCents: memberCents,
141	      reasons: [ReasonCode.APPROVED, ReasonCode.COPAY_APPLIED],
142	      explanation: `Copay: you pay the ${formatUsd(memberCents)} copay; the plan pays ${formatUsd(planCents)}.`,
143	      deltas: { deductibleIncCents: 0, oopIncCents: memberCents, limitInc: 0 },
144	    };
145	  } else {
146	    // Cycle 10–13 — coinsurance: the deductible draws first (when applies_deductible), then the
147	    // member pays `rate` of the remainder. Rounding lives only on the coinsurance share; `plan`
148	    // is computed last as `allowed − member`, so the shares always sum to allowed (no lost cent).
149	    const allowedCents = line.billedCents;
150	    const remainingDeductibleCents = Math.max(0, policy.deductibleCents - acc.deductibleMetCents);
151	    const dedPortionCents = rule.appliesDeductible
152	      ? Math.min(remainingDeductibleCents, allowedCents)
153	      : 0;
154	    const remainderCents = allowedCents - dedPortionCents;
155	    const coinsPortionCents = Math.round(rule.costShare.rate * remainderCents); // half-up
156	    const memberCents = dedPortionCents + coinsPortionCents;
157	    const planCents = allowedCents - memberCents;
158	
159	    const reasons: ReasonCode[] = [ReasonCode.APPROVED];
160	    if (dedPortionCents > 0) reasons.push(ReasonCode.DEDUCTIBLE_APPLIED);
161	    reasons.push(ReasonCode.COINSURANCE_APPLIED);
162	
163	    const ratePct = Math.round(rule.costShare.rate * 100);
164	    const dedNote = dedPortionCents > 0 ? `${formatUsd(dedPortionCents)} toward your deductible plus ` : "";
165	    result = {
166	      status: "APPROVED",
167	      payableCents: planCents,
168	      memberResponsibilityCents: memberCents,
169	      reasons,
170	      explanation: `Coinsurance: you pay ${formatUsd(memberCents)} (${dedNote}${ratePct}% of ${formatUsd(remainderCents)}); the plan pays ${formatUsd(planCents)}.`,
171	      deltas: { deductibleIncCents: dedPortionCents, oopIncCents: memberCents, limitInc: 0 },
172	    };
173	  }
